
from __future__ import annotations

from pathlib import Path
import sys

MONITOR_ENGINE_CODE = "\nfrom __future__ import annotations\n\nfrom dataclasses import dataclass\nfrom datetime import datetime, timedelta, timezone\nfrom typing import Any\n\nimport math\nimport pandas as pd\nimport requests\n\n\nSECTOR_ETF_MAP = {\n    \"Information Technology\": \"XLK\",\n    \"Communication Services\": \"XLC\",\n    \"Consumer Discretionary\": \"XLY\",\n    \"Consumer Staples\": \"XLP\",\n    \"Financials\": \"XLF\",\n    \"Health Care\": \"XLV\",\n    \"Industrials\": \"XLI\",\n    \"Energy\": \"XLE\",\n    \"Utilities\": \"XLU\",\n    \"Materials\": \"XLB\",\n    \"Real Estate\": \"XLRE\",\n}\n\n\nFALLBACK_METADATA = {\n    \"AAPL\": {\n        \"sector\": \"Information Technology\",\n        \"market_cap_tier\": \"Mega Cap\",\n        \"style\": \"Growth\",\n        \"region\": \"United States\",\n        \"beta\": 1.20,\n    },\n    \"NVDA\": {\n        \"sector\": \"Information Technology\",\n        \"market_cap_tier\": \"Mega Cap\",\n        \"style\": \"Growth\",\n        \"region\": \"United States\",\n        \"beta\": 1.75,\n    },\n    \"AVGO\": {\n        \"sector\": \"Information Technology\",\n        \"market_cap_tier\": \"Mega Cap\",\n        \"style\": \"Growth\",\n        \"region\": \"United States\",\n        \"beta\": 1.15,\n    },\n    \"AMZN\": {\n        \"sector\": \"Consumer Discretionary\",\n        \"market_cap_tier\": \"Mega Cap\",\n        \"style\": \"Growth\",\n        \"region\": \"United States\",\n        \"beta\": 1.30,\n    },\n    \"SPOT\": {\n        \"sector\": \"Communication Services\",\n        \"market_cap_tier\": \"Large Cap\",\n        \"style\": \"Growth\",\n        \"region\": \"International\",\n        \"beta\": 1.60,\n    },\n    \"GE\": {\n        \"sector\": \"Industrials\",\n        \"market_cap_tier\": \"Large Cap\",\n        \"style\": \"Value / Cyclical\",\n        \"region\": \"United States\",\n        \"beta\": 1.20,\n    },\n}\n\n\ndef _safe_float(value: Any, default: float = 0.0) -> float:\n    try:\n        if value is None:\n            return default\n        return float(value)\n    except Exception:\n        return default\n\n\ndef _download_chart(ticker: str, lookback_days: int = 400) -> pd.DataFrame:\n    end = int(datetime.now(timezone.utc).timestamp())\n    start = int((datetime.now(timezone.utc) - timedelta(days=lookback_days + 10)).timestamp())\n    url = f\"https://query1.finance.yahoo.com/v8/finance/chart/{ticker}\"\n\n    try:\n        r = requests.get(\n            url,\n            params={\n                \"period1\": start,\n                \"period2\": end,\n                \"interval\": \"1d\",\n                \"events\": \"history\",\n            },\n            timeout=15,\n            headers={\"User-Agent\": \"Mozilla/5.0\"},\n        )\n        r.raise_for_status()\n        data = r.json()\n        result = data.get(\"chart\", {}).get(\"result\", [])\n        if not result:\n            return pd.DataFrame()\n\n        payload = result[0]\n        timestamps = payload.get(\"timestamp\", [])\n        quote = payload.get(\"indicators\", {}).get(\"quote\", [{}])[0]\n\n        if not timestamps:\n            return pd.DataFrame()\n\n        df = pd.DataFrame(\n            {\n                \"date\": pd.to_datetime(timestamps, unit=\"s\", utc=True).normalize(),\n                \"open\": quote.get(\"open\", []),\n                \"high\": quote.get(\"high\", []),\n                \"low\": quote.get(\"low\", []),\n                \"close\": quote.get(\"close\", []),\n                \"volume\": quote.get(\"volume\", []),\n            }\n        )\n\n        df = df.dropna(subset=[\"close\"]).set_index(\"date\").sort_index()\n        return df.tail(lookback_days)\n\n    except Exception:\n        return pd.DataFrame()\n\n\ndef _download_quote_summary(ticker: str) -> dict[str, Any]:\n    url = f\"https://query1.finance.yahoo.com/v10/finance/quoteSummary/{ticker}\"\n\n    try:\n        r = requests.get(\n            url,\n            params={\"modules\": \"assetProfile,summaryDetail,price,defaultKeyStatistics\"},\n            timeout=15,\n            headers={\"User-Agent\": \"Mozilla/5.0\"},\n        )\n        r.raise_for_status()\n        data = r.json()\n        result = data.get(\"quoteSummary\", {}).get(\"result\", [])\n        if not result:\n            return {}\n\n        root = result[0]\n        profile = root.get(\"assetProfile\", {}) or {}\n        summary = root.get(\"summaryDetail\", {}) or {}\n        price = root.get(\"price\", {}) or {}\n        stats = root.get(\"defaultKeyStatistics\", {}) or {}\n\n        def raw(obj: dict[str, Any], key: str, default: Any = None) -> Any:\n            value = obj.get(key, default)\n            if isinstance(value, dict) and \"raw\" in value:\n                return value[\"raw\"]\n            return value\n\n        return {\n            \"sector\": profile.get(\"sector\"),\n            \"industry\": profile.get(\"industry\"),\n            \"country\": profile.get(\"country\"),\n            \"market_cap\": raw(price, \"marketCap\"),\n            \"beta\": raw(summary, \"beta\"),\n            \"forward_pe\": raw(summary, \"forwardPE\"),\n            \"trailing_pe\": raw(summary, \"trailingPE\"),\n            \"price_to_book\": raw(stats, \"priceToBook\"),\n        }\n\n    except Exception:\n        return {}\n\n\ndef _market_cap_tier(market_cap: float | None) -> str:\n    if market_cap is None or market_cap <= 0:\n        return \"Unknown\"\n    if market_cap >= 200_000_000_000:\n        return \"Mega Cap\"\n    if market_cap >= 10_000_000_000:\n        return \"Large Cap\"\n    if market_cap >= 2_000_000_000:\n        return \"Mid Cap\"\n    return \"Small Cap\"\n\n\ndef _style_bucket(forward_pe: float | None, price_to_book: float | None, fallback: str = \"Unknown\") -> str:\n    if forward_pe is None or forward_pe <= 0:\n        return fallback\n\n    if forward_pe >= 30:\n        return \"Growth\"\n    if forward_pe <= 18:\n        return \"Value\"\n    return \"Blend\"\n\n\ndef _pct_change(close: pd.Series, periods: int) -> float | None:\n    if close is None or len(close) <= periods:\n        return None\n    try:\n        return float((close.iloc[-1] / close.iloc[-periods - 1] - 1) * 100)\n    except Exception:\n        return None\n\n\ndef _distance_from_high(close: pd.Series, window: int) -> float | None:\n    if close.empty:\n        return None\n    recent = close.tail(window)\n    high = recent.max()\n    if high <= 0:\n        return None\n    return float((close.iloc[-1] / high - 1) * 100)\n\n\ndef _volume_ratio(df: pd.DataFrame, window: int = 30) -> float | None:\n    if df.empty or \"volume\" not in df.columns or len(df) < 5:\n        return None\n\n    volume = df[\"volume\"].dropna()\n    if len(volume) < 5:\n        return None\n\n    latest = volume.iloc[-1]\n    avg = volume.tail(window).mean()\n\n    if avg <= 0:\n        return None\n\n    return float(latest / avg)\n\n\ndef _get_item(item: Any, key: str, default: Any = None) -> Any:\n    if isinstance(item, dict):\n        return item.get(key, default)\n    return getattr(item, key, default)\n\n\ndef _earnings_days_map(earnings_calendar: list[Any]) -> dict[str, str]:\n    out = {}\n    today = datetime.now().date()\n\n    for item in earnings_calendar or []:\n        ticker = str(_get_item(item, \"ticker\", \"\")).upper()\n        date_raw = _get_item(item, \"date\")\n\n        if not ticker or not date_raw:\n            continue\n\n        try:\n            event_date = datetime.fromisoformat(str(date_raw)[:10]).date()\n            days = (event_date - today).days\n            if days >= 0:\n                out[ticker] = f\"{days} day(s)\"\n        except Exception:\n            continue\n\n    return out\n\n\ndef _sec_filings_map(sec_filings: list[Any]) -> dict[str, str]:\n    out = {}\n\n    for filing in sec_filings or []:\n        ticker = str(_get_item(filing, \"ticker\", \"\")).upper()\n        if not ticker:\n            continue\n\n        form = str(_get_item(filing, \"form_type\", \"\") or \"\")\n        signal = str(_get_item(filing, \"signal_type\", \"\") or \"\")\n        items = _get_item(filing, \"items_detected\", []) or []\n\n        if items:\n            label = f\"{form} / {', '.join(items)}\"\n        elif signal:\n            label = f\"{form} / {signal}\"\n        else:\n            label = form or \"Recent filing\"\n\n        if ticker not in out:\n            out[ticker] = label\n\n    return out\n\n\ndef build_holdings_change_monitor(\n    holdings: list[Any],\n    earnings_calendar: list[Any] | None = None,\n    sec_filings: list[Any] | None = None,\n    benchmark: str = \"SPY\",\n) -> dict[str, Any]:\n    earnings_map = _earnings_days_map(earnings_calendar or [])\n    sec_map = _sec_filings_map(sec_filings or [])\n\n    spy_chart = _download_chart(benchmark, lookback_days=400)\n    spy_close = spy_chart[\"close\"] if not spy_chart.empty else pd.Series(dtype=float)\n    spy_daily = _pct_change(spy_close, 1)\n    spy_weekly = _pct_change(spy_close, 5)\n\n    rows = []\n\n    for holding in holdings:\n        ticker = str(_get_item(holding, \"ticker\", \"\")).upper().strip()\n        shares = _safe_float(_get_item(holding, \"shares\", 0.0))\n\n        if not ticker:\n            continue\n\n        fallback = FALLBACK_METADATA.get(ticker, {})\n        chart = _download_chart(ticker, lookback_days=400)\n        quote = _download_quote_summary(ticker)\n\n        close = chart[\"close\"] if not chart.empty else pd.Series(dtype=float)\n        latest_price = float(close.iloc[-1]) if not close.empty else None\n\n        sector = quote.get(\"sector\") or fallback.get(\"sector\") or \"Other\"\n        sector_etf = SECTOR_ETF_MAP.get(sector)\n        sector_weekly = None\n\n        if sector_etf:\n            sector_chart = _download_chart(sector_etf, lookback_days=30)\n            if not sector_chart.empty:\n                sector_weekly = _pct_change(sector_chart[\"close\"], 5)\n\n        daily = _pct_change(close, 1)\n        weekly = _pct_change(close, 5)\n\n        market_cap = quote.get(\"market_cap\")\n        market_cap_tier = _market_cap_tier(_safe_float(market_cap, 0.0)) if market_cap else fallback.get(\"market_cap_tier\", \"Unknown\")\n\n        beta = quote.get(\"beta\")\n        if beta is None:\n            beta = fallback.get(\"beta\")\n\n        style = _style_bucket(\n            quote.get(\"forward_pe\"),\n            quote.get(\"price_to_book\"),\n            fallback=fallback.get(\"style\", \"Unknown\"),\n        )\n\n        country = quote.get(\"country\") or fallback.get(\"region\") or \"Unknown\"\n        region = \"United States\" if str(country).lower() in {\"united states\", \"united states of america\", \"usa\"} else \"International\"\n\n        value = shares * latest_price if latest_price is not None else 0.0\n\n        rows.append(\n            {\n                \"ticker\": ticker,\n                \"sector\": sector,\n                \"sector_etf\": sector_etf or \"N/A\",\n                \"latest_price\": latest_price,\n                \"shares\": shares,\n                \"market_value\": value,\n                \"daily_move_pct\": daily,\n                \"weekly_move_pct\": weekly,\n                \"weekly_vs_spy_pct\": weekly - spy_weekly if weekly is not None and spy_weekly is not None else None,\n                \"weekly_vs_sector_etf_pct\": weekly - sector_weekly if weekly is not None and sector_weekly is not None else None,\n                \"earnings_proximity\": earnings_map.get(ticker, \"None found\"),\n                \"recent_sec_filing\": sec_map.get(ticker, \"None found\"),\n                \"volume_vs_30d_avg\": _volume_ratio(chart, 30),\n                \"distance_from_52w_high_pct\": _distance_from_high(close, 252),\n                \"drawdown_from_63d_high_pct\": _distance_from_high(close, 63),\n                \"market_cap_tier\": market_cap_tier,\n                \"style\": style,\n                \"beta\": beta,\n                \"region\": region,\n                \"country\": country,\n            }\n        )\n\n    df = pd.DataFrame(rows)\n\n    if df.empty:\n        return {\n            \"status\": \"Unavailable\",\n            \"message\": \"No holdings data available.\",\n            \"holdings\": [],\n            \"exposure\": {},\n        }\n\n    total_value = df[\"market_value\"].sum()\n    df[\"portfolio_weight_pct\"] = df[\"market_value\"] / total_value * 100 if total_value > 0 else 0.0\n\n    exposure = build_portfolio_exposure_dashboard(df)\n\n    return {\n        \"status\": \"Ready\",\n        \"message\": \"Holdings change monitor completed.\",\n        \"benchmark\": benchmark,\n        \"holdings\": df.sort_values(\"portfolio_weight_pct\", ascending=False).to_dict(\"records\"),\n        \"exposure\": exposure,\n    }\n\n\ndef build_portfolio_exposure_dashboard(holdings_df: pd.DataFrame) -> dict[str, Any]:\n    df = holdings_df.copy()\n\n    total_value = df[\"market_value\"].sum()\n    if total_value <= 0:\n        total_value = 1.0\n\n    sector = (\n        df.groupby(\"sector\", as_index=False)[\"market_value\"]\n        .sum()\n        .assign(weight_pct=lambda x: x[\"market_value\"] / total_value * 100)\n        .sort_values(\"weight_pct\", ascending=False)\n    )\n\n    market_cap = (\n        df.groupby(\"market_cap_tier\", as_index=False)[\"market_value\"]\n        .sum()\n        .assign(weight_pct=lambda x: x[\"market_value\"] / total_value * 100)\n        .sort_values(\"weight_pct\", ascending=False)\n    )\n\n    style = (\n        df.groupby(\"style\", as_index=False)[\"market_value\"]\n        .sum()\n        .assign(weight_pct=lambda x: x[\"market_value\"] / total_value * 100)\n        .sort_values(\"weight_pct\", ascending=False)\n    )\n\n    region = (\n        df.groupby(\"region\", as_index=False)[\"market_value\"]\n        .sum()\n        .assign(weight_pct=lambda x: x[\"market_value\"] / total_value * 100)\n        .sort_values(\"weight_pct\", ascending=False)\n    )\n\n    top_3_weight = float(df.sort_values(\"market_value\", ascending=False).head(3)[\"market_value\"].sum() / total_value * 100)\n    max_single_name = float(df[\"market_value\"].max() / total_value * 100)\n\n    df[\"beta_numeric\"] = df[\"beta\"].apply(lambda x: _safe_float(x, 1.0))\n    portfolio_beta = float((df[\"market_value\"] / total_value * df[\"beta_numeric\"]).sum())\n\n    return {\n        \"total_value\": float(total_value),\n        \"cash_pct\": 0.0,\n        \"single_name_concentration_pct\": max_single_name,\n        \"top_3_concentration_pct\": top_3_weight,\n        \"portfolio_beta\": portfolio_beta,\n        \"sector_exposure\": sector.to_dict(\"records\"),\n        \"market_cap_exposure\": market_cap.to_dict(\"records\"),\n        \"style_exposure\": style.to_dict(\"records\"),\n        \"region_exposure\": region.to_dict(\"records\"),\n    }\n"
MONITOR_PAGE_CODE = "\ndef render_monitor() -> None:\n    st.markdown(\"### Holdings Change Monitor\")\n    st.caption(\"Purely factual monitor: price changes, SPY/sector comparison, catalysts, SEC filings, volume, 52-week distance, drawdowns, and portfolio exposure.\")\n\n    try:\n        from app.config.portfolio import load_portfolio\n        from app.config.settings import settings\n        from app.data.earnings import get_upcoming_earnings\n        from app.data.sec_filings import get_sec_filings\n        from app.data.holdings_monitor import build_holdings_change_monitor\n\n        holdings = load_portfolio(settings.portfolio_file)\n        tickers = [holding.ticker for holding in holdings]\n\n        benchmark = st.text_input(\"Benchmark\", value=\"SPY\").upper().strip()\n\n        with st.spinner(\"Loading factual holdings monitor...\"):\n            earnings = get_upcoming_earnings(tickers, days_ahead=45)\n            sec = get_sec_filings(tickers, lookback_days=45, max_filings_per_ticker=3)\n            result = build_holdings_change_monitor(\n                holdings,\n                earnings_calendar=earnings,\n                sec_filings=sec,\n                benchmark=benchmark,\n            )\n\n        if result.get(\"status\") != \"Ready\":\n            st.warning(result.get(\"message\", \"Monitor unavailable.\"))\n            return\n\n        holdings_df = pd.DataFrame(result.get(\"holdings\", []))\n        exposure = result.get(\"exposure\", {})\n\n        st.divider()\n        st.markdown(\"#### Portfolio Exposure Dashboard\")\n\n        c1, c2, c3, c4 = st.columns(4)\n\n        with c1:\n            st.metric(\"Total Value\", f\"${exposure.get('total_value', 0):,.2f}\")\n\n        with c2:\n            st.metric(\"Largest Position\", f\"{exposure.get('single_name_concentration_pct', 0):.2f}%\")\n\n        with c3:\n            st.metric(\"Top 3 Concentration\", f\"{exposure.get('top_3_concentration_pct', 0):.2f}%\")\n\n        with c4:\n            st.metric(\"Portfolio Beta\", f\"{exposure.get('portfolio_beta', 0):.2f}\")\n\n        e1, e2 = st.columns(2)\n\n        with e1:\n            sector_df = pd.DataFrame(exposure.get(\"sector_exposure\", []))\n            st.markdown(\"##### Sector Exposure\")\n            if not sector_df.empty:\n                chart = sector_df.set_index(\"sector\")[[\"weight_pct\"]].rename(columns={\"weight_pct\": \"Weight (%)\"})\n                st.bar_chart(chart, height=280)\n                st.dataframe(_format_table_for_display(sector_df), use_container_width=True, hide_index=True)\n\n        with e2:\n            cap_df = pd.DataFrame(exposure.get(\"market_cap_exposure\", []))\n            st.markdown(\"##### Market Cap Exposure\")\n            if not cap_df.empty:\n                chart = cap_df.set_index(\"market_cap_tier\")[[\"weight_pct\"]].rename(columns={\"weight_pct\": \"Weight (%)\"})\n                st.bar_chart(chart, height=280)\n                st.dataframe(_format_table_for_display(cap_df), use_container_width=True, hide_index=True)\n\n        e3, e4 = st.columns(2)\n\n        with e3:\n            style_df = pd.DataFrame(exposure.get(\"style_exposure\", []))\n            st.markdown(\"##### Growth / Value Tilt\")\n            if not style_df.empty:\n                chart = style_df.set_index(\"style\")[[\"weight_pct\"]].rename(columns={\"weight_pct\": \"Weight (%)\"})\n                st.bar_chart(chart, height=280)\n                st.dataframe(_format_table_for_display(style_df), use_container_width=True, hide_index=True)\n\n        with e4:\n            region_df = pd.DataFrame(exposure.get(\"region_exposure\", []))\n            st.markdown(\"##### Geographic Exposure\")\n            if not region_df.empty:\n                chart = region_df.set_index(\"region\")[[\"weight_pct\"]].rename(columns={\"weight_pct\": \"Weight (%)\"})\n                st.bar_chart(chart, height=280)\n                st.dataframe(_format_table_for_display(region_df), use_container_width=True, hide_index=True)\n\n        st.divider()\n        st.markdown(\"#### Holdings Change Monitor\")\n\n        if holdings_df.empty:\n            st.info(\"No holdings monitor rows available.\")\n            return\n\n        display_cols = [\n            \"ticker\",\n            \"sector\",\n            \"sector_etf\",\n            \"portfolio_weight_pct\",\n            \"latest_price\",\n            \"market_value\",\n            \"daily_move_pct\",\n            \"weekly_move_pct\",\n            \"weekly_vs_spy_pct\",\n            \"weekly_vs_sector_etf_pct\",\n            \"earnings_proximity\",\n            \"recent_sec_filing\",\n            \"volume_vs_30d_avg\",\n            \"distance_from_52w_high_pct\",\n            \"drawdown_from_63d_high_pct\",\n            \"market_cap_tier\",\n            \"style\",\n            \"beta\",\n            \"region\",\n        ]\n        display_cols = [c for c in display_cols if c in holdings_df.columns]\n\n        clean = holdings_df[display_cols].rename(columns={\n            \"ticker\": \"Ticker\",\n            \"sector\": \"Sector\",\n            \"sector_etf\": \"Sector ETF\",\n            \"portfolio_weight_pct\": \"Portfolio Weight (%)\",\n            \"latest_price\": \"Latest Price ($)\",\n            \"market_value\": \"Market Value ($)\",\n            \"daily_move_pct\": \"Daily Move (%)\",\n            \"weekly_move_pct\": \"Weekly Move (%)\",\n            \"weekly_vs_spy_pct\": \"Weekly vs SPY (%)\",\n            \"weekly_vs_sector_etf_pct\": \"Weekly vs Sector ETF (%)\",\n            \"earnings_proximity\": \"Earnings Proximity\",\n            \"recent_sec_filing\": \"Recent SEC Filing\",\n            \"volume_vs_30d_avg\": \"Volume vs 30D Avg (x)\",\n            \"distance_from_52w_high_pct\": \"Distance from 52W High (%)\",\n            \"drawdown_from_63d_high_pct\": \"Drawdown from 63D High (%)\",\n            \"market_cap_tier\": \"Market Cap Tier\",\n            \"style\": \"Growth / Value\",\n            \"beta\": \"Beta\",\n            \"region\": \"Region\",\n        })\n\n        for col in [\n            \"Portfolio Weight (%)\",\n            \"Daily Move (%)\",\n            \"Weekly Move (%)\",\n            \"Weekly vs SPY (%)\",\n            \"Weekly vs Sector ETF (%)\",\n            \"Distance from 52W High (%)\",\n            \"Drawdown from 63D High (%)\",\n        ]:\n            if col in clean.columns:\n                clean[col] = clean[col].map(lambda x: \"\" if pd.isna(x) else f\"{float(x):+.2f}%\")\n\n        for col in [\"Latest Price ($)\", \"Market Value ($)\"]:\n            if col in clean.columns:\n                clean[col] = clean[col].map(lambda x: \"\" if pd.isna(x) else f\"${float(x):,.2f}\")\n\n        if \"Volume vs 30D Avg (x)\" in clean.columns:\n            clean[\"Volume vs 30D Avg (x)\"] = clean[\"Volume vs 30D Avg (x)\"].map(lambda x: \"\" if pd.isna(x) else f\"{float(x):.2f}x\")\n\n        if \"Beta\" in clean.columns:\n            clean[\"Beta\"] = clean[\"Beta\"].map(lambda x: \"\" if pd.isna(x) else f\"{float(x):.2f}\")\n\n        st.dataframe(clean, use_container_width=True, hide_index=True)\n\n    except Exception as exc:\n        st.error(f\"Holdings monitor failed: {exc}\")\n"


def backup(path: Path) -> None:
    if path.exists():
        path.with_suffix(path.suffix + ".bak_monitor").write_text(path.read_text(encoding="utf-8"), encoding="utf-8")


def install_module() -> None:
    target = Path("app/data/holdings_monitor.py")
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(MONITOR_ENGINE_CODE, encoding="utf-8")
    print("OK | app/data/holdings_monitor.py written")


def patch_control_center() -> None:
    path = Path("newsletter_control_center.py")
    if not path.exists():
        raise SystemExit("ERROR | newsletter_control_center.py not found")

    backup(path)
    text = path.read_text(encoding="utf-8")

    if "def render_monitor() -> None:" not in text:
        if "\ndef main() -> None:" not in text:
            raise SystemExit("ERROR | could not find main()")
        text = text.replace("\ndef main() -> None:", MONITOR_PAGE_CODE + "\ndef main() -> None:", 1)

    if '"Monitor",' not in text:
        for anchor in [
            '        "Portfolio",\n',
            '        "Analytics",\n',
            '        "Construction",\n',
        ]:
            if anchor in text:
                text = text.replace(anchor, anchor + '        "Monitor",\n', 1)
                break
        else:
            raise SystemExit("ERROR | could not add Monitor to nav_pages")

    if 'elif page == "Monitor":' not in text:
        for old, new in [
            ('    elif page == "Portfolio":\n        render_portfolio(df, portfolio_path)\n',
             '    elif page == "Portfolio":\n        render_portfolio(df, portfolio_path)\n    elif page == "Monitor":\n        render_monitor()\n'),
            ('    elif page == "Analytics":\n        render_analytics()\n',
             '    elif page == "Analytics":\n        render_analytics()\n    elif page == "Monitor":\n        render_monitor()\n'),
            ('    elif page == "Construction":\n        render_construction()\n',
             '    elif page == "Construction":\n        render_construction()\n    elif page == "Monitor":\n        render_monitor()\n'),
        ]:
            if old in text:
                text = text.replace(old, new, 1)
                break
        else:
            raise SystemExit("ERROR | could not add Monitor route")

    path.write_text(text, encoding="utf-8")
    print("OK | newsletter_control_center.py patched")


def verify() -> bool:
    checks = {}
    checks["monitor module exists"] = Path("app/data/holdings_monitor.py").exists()

    text = Path("newsletter_control_center.py").read_text(encoding="utf-8")
    checks["Monitor nav"] = '"Monitor"' in text
    checks["render_monitor"] = "def render_monitor() -> None:" in text
    checks["Monitor route"] = 'elif page == "Monitor":' in text

    try:
        from app.data.holdings_monitor import build_holdings_change_monitor
        checks["monitor import works"] = True
    except Exception as exc:
        print(f"FAIL | monitor import error: {exc}")
        checks["monitor import works"] = False

    print("\nVERIFY")
    ok_all = True
    for name, ok in checks.items():
        print(("PASS" if ok else "FAIL") + f" | {name}")
        ok_all = ok_all and ok

    return ok_all


def main() -> None:
    if "--verify" in sys.argv:
        raise SystemExit(0 if verify() else 1)

    print("Installing holdings monitor from:", Path.cwd())
    install_module()
    patch_control_center()
    ok = verify()

    print("\nNEXT:")
    print("python install_holdings_monitor.py --verify")
    print("python -m streamlit run newsletter_control_center.py")

    raise SystemExit(0 if ok else 1)


if __name__ == "__main__":
    main()
